let StripeModel={creditcard:{async createCreditCard(data){let payload={email:data.email,first_name:stripeFirstName.value,last_name:stripeLastName.value,stripe_credit_card:data.creditcard,card_brand:data.card_brand},response=await StripeServices.createCreditCard({payload:payload});return response.state||App.events.notyf("error","Failed to create creditcard."),response},async removeCreditCard(id){let payload={id:id,properties:{is_enabled:!1}},response=await StripeServices.deleteCreditCard({payload:payload});return response.state||App.events.notyf("error","Failed to delete creditcard."),response},async updateCreditCard(payload){let response=await StripeServices.updateCreditCard({payload:payload});return response.state||App.events.notyf("error","Failed to update creditcard."),response}},customer:{}};window.StripeModel=StripeModel;